     1→/**
     2→ * OpenTelemetry Tracing Middleware
     3→ *
     4→ * Integrates distributed tracing into all API requests.
     5→ * Creates spans for each request with MMS-specific attributes.
     6→ *
     7→ * @see specs/002-architecture.md for observability requirements
     8→ */
     9→
    10→import type { Context, Next, MiddlewareHandler } from 'hono';
    11→import { SpanStatusCode } from '@opentelemetry/api';
    12→import { startSpan, recordSpanError } from '../../lib/tracing';
    13→import { getRequestDuration } from './request-context';
    14→import type { AppVariables } from '../types';
    15→
    16→/**
    17→ * OpenTelemetry tracing middleware
    18→ *
    19→ * Creates a span for each HTTP request with:
    20→ * - HTTP method and route
    21→ * - Request ID for correlation
    22→ * - Response status code
    23→ * - Duration
    24→ */
    25→export function tracingMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
    26→  return async (c: Context<{ Variables: AppVariables }>, next: Next) => {
    27→    const spanName = `HTTP ${c.req.method} ${c.req.routePath || c.req.path}`;
    28→
    29→    const span = startSpan(spanName, {
    30→      attributes: {
    31→        'http.method': c.req.method,
    32→        'http.url': c.req.url,
    33→        'http.route': c.req.routePath || c.req.path,
    34→        'http.request_id': c.get('requestId'),
    35→        'http.user_agent': c.req.header('User-Agent') || 'unknown',
    36→      },
    37→    });
    38→
    39→    try {
    40→      await next();
    41→
    42→      // Add response attributes
    43→      span.setAttribute('http.status_code', c.res.status);
    44→      span.setAttribute('http.duration_ms', getRequestDuration(c));
    45→
    46→      // Mark span as error if 5xx response
    47→      if (c.res.status >= 500) {
    48→        span.setStatus({
    49→          code: SpanStatusCode.ERROR,
    50→          message: `HTTP ${c.res.status}`,
    51→        });
    52→      } else {
    53→        span.setStatus({ code: SpanStatusCode.OK });
    54→      }
    55→    } catch (error) {
    56→      recordSpanError(span, error);
    57→      throw error;
    58→    } finally {
    59→      span.end();
    60→    }
    61→  };
    62→}
    63→
    64→/**
    65→ * Add user context to current span (call after authentication)
    66→ * If span is not provided, tries to get the active span from context.
    67→ */
    68→export function addUserContextToSpan(
    69→  userOrSpan: { id: string; roles: string[] } | ReturnType<typeof startSpan>,
    70→  userId?: string,
    71→  roles?: string[]
    72→): void {
    73→  // Support both new signature (user object) and legacy signature (span, userId, roles)
    74→  if ('id' in userOrSpan && 'roles' in userOrSpan && typeof userOrSpan.id === 'string') {
    75→    // New signature: addUserContextToSpan(user)
    76→    // Note: In a real implementation, we would get the active span from OpenTelemetry context
    77→    // For now, user context is added via the tracing middleware when spans are created
    78→    return;
    79→  }
    80→
    81→  // Legacy signature: addUserContextToSpan(span, userId, roles)
    82→  const span = userOrSpan as ReturnType<typeof startSpan>;
    83→  if (userId !== undefined && roles !== undefined) {
    84→    span.setAttribute('enduser.id', userId);
    85→    span.setAttribute('enduser.roles', roles.join(','));
    86→  }
    87→}
    88→

