/**
 * Authentication Middleware
 *
 * Provides JWT-based authentication for protected API routes.
 * Validates access tokens and populates user context for authorization.
 *
 * Usage:
 * - Apply `authMiddleware()` to routes requiring authentication
 * - Use `requireRole('ADMIN')` for role-based access control
 * - Use `requireDepotAccess()` for depot-scoped operations
 *
 * @see specs/005-api.md Section 5.2 (Authentication)
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import { verify } from 'hono/jwt';
import type { AppVariables, AuthUser } from '../types';
import { getRequestId } from './request-context';
import { addUserContextToSpan } from './tracing';
import { error, ErrorCodes } from '../types';
import { AuthorizationError } from '../../lib/errors';
import type { JwtPayload } from '../../services/auth';

/**
 * JWT secret - must match AuthService
 */
const JWT_SECRET = process.env.JWT_SECRET || 'mms-development-secret-change-in-production';

/** JWT signing algorithm */
const JWT_ALGORITHM = 'HS256' as const;

/**
 * Get authenticated user from context
 */
export function getAuthUser(c: Context<{ Variables: AppVariables }>): AuthUser | undefined {
  return c.get('user');
}

/**
 * Require authenticated user - throws if not present
 */
export function requireAuthUser(c: Context<{ Variables: AppVariables }>): AuthUser {
  const user = c.get('user');
  if (!user) {
    throw new AuthorizationError('Authentication required');
  }
  return user;
}

/**
 * Authentication middleware
 *
 * Validates Bearer token in Authorization header and populates user context.
 * Call this before any route handler that requires authentication.
 */
export function authMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<Response | void> => {
    const requestId = getRequestId(c);
    const authHeader = c.req.header('authorization');

    // Check for Authorization header
    if (!authHeader || !authHeader.startsWith('Bearer ')) {
      return c.json(
        error(
          ErrorCodes.UNAUTHORIZED,
          'Authorization header with Bearer token is required',
          requestId
        ),
        401 as const
      );
    }

    const token = authHeader.substring(7); // Remove 'Bearer ' prefix

    try {
      // Verify JWT token
      const verified = await verify(token, JWT_SECRET, JWT_ALGORITHM);
      const payload = verified as JwtPayload;

      // Build user context
      const user: AuthUser = {
        id: payload.sub,
        email: payload.email,
        roles: payload.roles,
        depotId: payload.depotId || undefined,
      };

      // Set user in context
      c.set('user', user);

      // Add to OpenTelemetry span
      addUserContextToSpan(user);

      await next();
    } catch (err) {
      if (err instanceof Error) {
        if (err.message.includes('expired')) {
          return c.json(
            error(ErrorCodes.UNAUTHORIZED, 'Access token has expired', requestId),
            401 as const
          );
        }
        if (err.message.includes('invalid') || err.message.includes('signature')) {
          return c.json(
            error(ErrorCodes.UNAUTHORIZED, 'Invalid access token', requestId),
            401 as const
          );
        }
      }
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Authentication failed', requestId),
        401 as const
      );
    }
  };
}

/**
 * Optional authentication middleware
 *
 * Validates Bearer token if present but doesn't require it.
 * Populates user context when token is valid.
 */
export function optionalAuthMiddleware(): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<void> => {
    const authHeader = c.req.header('authorization');

    if (authHeader && authHeader.startsWith('Bearer ')) {
      const token = authHeader.substring(7);

      try {
        const verified = await verify(token, JWT_SECRET, JWT_ALGORITHM);
        const payload = verified as JwtPayload;

        const user: AuthUser = {
          id: payload.sub,
          email: payload.email,
          roles: payload.roles,
          depotId: payload.depotId || undefined,
        };

        c.set('user', user);
        addUserContextToSpan(user);
      } catch {
        // Token is invalid but we don't require auth - continue without user context
      }
    }

    await next();
  };
}

/**
 * Role-based authorization middleware
 *
 * Requires user to have at least one of the specified roles.
 * Must be used after authMiddleware().
 *
 * @param allowedRoles - Array of role names that are permitted
 */
export function requireRole(
  ...allowedRoles: string[]
): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<Response | void> => {
    const requestId = getRequestId(c);
    const user = c.get('user');

    if (!user) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Authentication required', requestId),
        401 as const
      );
    }

    // Check if user has at least one of the allowed roles
    const hasRole = user.roles.some((role) => allowedRoles.includes(role));

    if (!hasRole) {
      return c.json(
        error(
          ErrorCodes.FORBIDDEN,
          `Access denied. Required role: ${allowedRoles.join(' or ')}`,
          requestId,
          { requiredRoles: allowedRoles, userRoles: user.roles }
        ),
        403 as const
      );
    }

    await next();
  };
}

/**
 * Depot access authorization middleware
 *
 * Validates that user has access to the depot specified in the request.
 * SYSTEM_ADMIN and PLANNER roles have access to all depots.
 *
 * @param depotIdParam - Name of the route parameter containing depot ID
 */
export function requireDepotAccess(
  depotIdParam: string = 'depotId'
): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<Response | void> => {
    const requestId = getRequestId(c);
    const user = c.get('user');

    if (!user) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Authentication required', requestId),
        401 as const
      );
    }

    // System admins and planners can access all depots
    if (user.roles.includes('SYSTEM_ADMIN') || user.roles.includes('PLANNER')) {
      await next();
      return;
    }

    // Get depot ID from route parameter or query
    const depotId = c.req.param(depotIdParam) || c.req.query(depotIdParam);

    if (!depotId) {
      // No depot specified - allow access
      await next();
      return;
    }

    // Check if user has access to this depot
    if (user.depotId && user.depotId !== depotId) {
      return c.json(
        error(
          ErrorCodes.FORBIDDEN,
          `Access denied to depot: ${depotId}`,
          requestId,
          { requestedDepot: depotId, userDepot: user.depotId }
        ),
        403 as const
      );
    }

    await next();
  };
}

/**
 * Permission-based authorization middleware
 *
 * Validates that user has specific permissions.
 * Permissions are stored in role definitions.
 *
 * @param resource - Resource name (e.g., 'pm_schedule')
 * @param action - Action name (e.g., 'write', 'delete')
 */
export function requirePermission(
  resource: string,
  action: string
): MiddlewareHandler<{ Variables: AppVariables }> {
  return async (c: Context<{ Variables: AppVariables }>, next: Next): Promise<Response | void> => {
    const requestId = getRequestId(c);
    const user = c.get('user');

    if (!user) {
      return c.json(
        error(ErrorCodes.UNAUTHORIZED, 'Authentication required', requestId),
        401 as const
      );
    }

    // System admins have all permissions
    if (user.roles.includes('SYSTEM_ADMIN')) {
      await next();
      return;
    }

    // For now, permission checking is role-based
    // In a full implementation, we would look up role permissions from the database
    const permissionMap: Record<string, Record<string, string[]>> = {
      pm_schedule: {
        read: ['PLANNER', 'DEPOT_MANAGER', 'VIEWER'],
        write: ['PLANNER', 'DEPOT_MANAGER'],
        delete: ['PLANNER'],
      },
      baseline: {
        read: ['PLANNER', 'DEPOT_MANAGER', 'VIEWER'],
        write: ['PLANNER'],
        delete: ['PLANNER'],
      },
      train: {
        read: ['PLANNER', 'DEPOT_MANAGER', 'VIEWER', 'TECHNICIAN'],
        write: ['PLANNER', 'DEPOT_MANAGER'],
      },
      optimizer: {
        run: ['PLANNER'],
      },
    };

    const allowedRoles = permissionMap[resource]?.[action] || [];

    const hasPermission = user.roles.some((role) => allowedRoles.includes(role));

    if (!hasPermission) {
      return c.json(
        error(
          ErrorCodes.FORBIDDEN,
          `Permission denied: ${resource}:${action}`,
          requestId,
          { resource, action, userRoles: user.roles }
        ),
        403 as const
      );
    }

    await next();
  };
}

