   266→      assignedDepot: pm.assignedDepot
   267→        ? {
   268→            id: pm.assignedDepot.id,
   269→            code: pm.assignedDepot.code,
   270→            name: pm.assignedDepot.name,
   271→          }
   272→        : null,
   273→      assignedTrack: pm.assignedTrack
   274→        ? {
