/**
 * Rate Limiter Middleware
 *
 * Implements rate limiting using Redis sliding window counter algorithm.
 * Protects the API from abuse with configurable limits per user/IP.
 *
 * @see specs/005-api.md - Rate Limiting: 100 requests/minute per user
 */

import type { Context, Next, MiddlewareHandler } from 'hono';
import type { AppVariables } from '../types';
import { getRedisClient } from '../../lib/redis/connection';
import { logger } from '../../lib/logging/logger';
import { rateLimitMetrics } from '../../lib/metrics';

/**
 * Rate limiter configuration
 */
export interface RateLimitConfig {
  /** Maximum requests allowed per window */
  limit: number;
  /** Window duration in seconds */
  windowSeconds: number;
  /** Custom key generator function */
  keyGenerator?: (c: Context<{ Variables: AppVariables }>) => string;
  /** Skip rate limiting for certain requests */
  skip?: (c: Context<{ Variables: AppVariables }>) => boolean;
  /** Redis key prefix */
  keyPrefix?: string;
}

/**
 * Default rate limit configuration
 * 100 requests per minute per user (per spec 005)
 */
const DEFAULT_CONFIG: RateLimitConfig = {
  limit: 100,
  windowSeconds: 60,
  keyPrefix: 'ratelimit:',
};

/**
 * Rate limit info added to response headers
 */
export interface RateLimitInfo {
  limit: number;
  remaining: number;
  reset: number;
}

/**
 * Get rate limit identifier for a request
 * Uses user ID if authenticated, otherwise uses IP address
 */
function getDefaultKey(c: Context<{ Variables: AppVariables }>): string {
  const user = c.get('user');
  if (user?.id) {
    return `user:${user.id}`;
  }

  // Fallback to IP address for unauthenticated requests
  const forwarded = c.req.header('x-forwarded-for');
  const ip = forwarded?.split(',')[0]?.trim() || 'unknown';
  return `ip:${ip}`;
}

/**
 * Calculate reset timestamp (end of current window)
 */
function getResetTimestamp(windowSeconds: number): number {
  const windowStart = Math.floor(Date.now() / 1000 / windowSeconds) * windowSeconds;
  return windowStart + windowSeconds;
}

/**
 * Check rate limit and update counter using Redis
 *
 * Uses a sliding window approach with two adjacent windows
 * for smoother rate limiting near window boundaries.
 */
async function checkRateLimit(
  key: string,
  limit: number,
  windowSeconds: number
): Promise<{ allowed: boolean; remaining: number; reset: number }> {
  const redis = getRedisClient();
  const now = Date.now() / 1000;
  const windowStart = Math.floor(now / windowSeconds) * windowSeconds;
  const currentWindowKey = `${key}:${windowStart}`;
  const previousWindowKey = `${key}:${windowStart - windowSeconds}`;

  try {
    // Get current and previous window counts
    const pipeline = redis.pipeline();
    pipeline.get(currentWindowKey);
    pipeline.get(previousWindowKey);
    pipeline.incr(currentWindowKey);
    pipeline.expire(currentWindowKey, windowSeconds * 2);

    const results = await pipeline.exec();

